import React, { useState } from "react";

// Пример иерархической структуры директорий и файлов
const directories = [
    {
        name: "Documents",
        subdirectories: [
            {
                name: "Work",
                files: ["report.docx", "budget.xlsx"],
            },
            {
                name: "Personal",
                files: ["letter.txt", "cv.pdf"],
            },
        ],
    },
    {
        name: "Downloads",
        subdirectories: [
            {
                name: "Images",
                files: ["photo1.jpg", "photo2.png"],
            },
            {
                name: "Videos",
                files: ["video1.mp4", "video2.mkv"],
            },
        ],
    },
];

const Home = () => {
    // Состояния для выбранной директории и выбранного файла
    const [selectedDir, setSelectedDir] = useState(null);
    const [selectedFile, setSelectedFile] = useState(null);

    // Функция для выбора директории
    const handleDirectorySelect = (dir) => {
        setSelectedDir(dir);
        setSelectedFile(null); // При смене директории сбрасываем выбранный файл
    };

    // Функция для выбора файла
    const handleFileSelect = (file) => {
        setSelectedFile(file);
    };

    return (
        <div style={styles.container}>
            {/* Боковой раздел */}
            <div style={styles.sidebar}>
                <h3>Директории</h3>
                <ul style={styles.dirList}>
                    {directories.map((dir, idx) => (
                        <li key={idx}>
                            <button
                                style={styles.button}
                                onClick={() => handleDirectorySelect(dir)}
                            >
                                {dir.name}
                            </button>
                            {/* Показываем подкаталоги только если выбранная директория */}
                            {selectedDir === dir && (
                                <ul style={styles.subDirList}>
                                    {dir.subdirectories.map(
                                        (subDir, subIdx) => (
                                            <li key={subIdx}>
                                                <button
                                                    style={styles.button}
                                                    onClick={() =>
                                                        handleDirectorySelect(
                                                            subDir
                                                        )
                                                    }
                                                >
                                                    {subDir.name}
                                                </button>
                                            </li>
                                        )
                                    )}
                                </ul>
                            )}
                        </li>
                    ))}
                </ul>
            </div>

            {/* Основной раздел */}
            <div style={styles.mainContent}>
                {selectedDir ? (
                    <>
                        <h3>Файлы в {selectedDir.name}</h3>
                        <ul style={styles.fileList}>
                            {selectedDir.subdirectories &&
                                selectedDir.subdirectories.map(
                                    (subDir, idx) => (
                                        <div key={idx}>
                                            <h4>{subDir.name}</h4>
                                            <ul>
                                                {subDir.files.map(
                                                    (file, fileIdx) => (
                                                        <li key={fileIdx}>
                                                            <button
                                                                style={
                                                                    styles.button
                                                                }
                                                                onClick={() =>
                                                                    handleFileSelect(
                                                                        file
                                                                    )
                                                                }
                                                            >
                                                                {file}
                                                            </button>
                                                        </li>
                                                    )
                                                )}
                                            </ul>
                                        </div>
                                    )
                                )}
                        </ul>
                    </>
                ) : (
                    <p>Выберите директорию для отображения файлов.</p>
                )}
            </div>

            {/* Нижний раздел */}
            <div style={styles.footer}>
                {selectedFile ? (
                    <div>
                        <h4>Содержимое файла: {selectedFile}</h4>
                        <p>Здесь будет отображаться содержимое файла...</p>
                    </div>
                ) : (
                    <p>Выберите файл для просмотра содержимого.</p>
                )}
            </div>
        </div>
    );
};

export default Home;
